import React, { useState } from 'react';
import { municipiosIBGE } from './municipiosIBGE';
import MenuLateral from './MenuLateral';

const campos = [
  'Ano',
  'Código da Estação',
  'Número da estação na Anatel',
  'LATITUDE',
  'LONGITUDE',
  'ESTADO',
  'MUNICIPIO',
  'Tipo de Estação',
  'Status',
  'Data de Ativação',
  'Responsável Técnico',
  'Contato',
  'Observações'
];

export default function EstacoesInfra() {
  const [valores, setValores] = useState(Array(campos.length).fill(''));

  // Recupera razão social e CNPJ do localStorage, igual aos outros módulos
  let razaoSocial = '';
  let cnpj = '';
  try {
    const salvo = localStorage.getItem('clienteSelecionado');
    if (salvo) {
      const obj = JSON.parse(salvo);
      razaoSocial = obj.razaoSocial || '';
      cnpj = obj.cnpj || '';
    }
  } catch {}

  const handleChange = (idx, value) => {
    const novo = [...valores];
    novo[idx] = value;
    setValores(novo);
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    // Aqui você pode salvar os dados ou enviar para API
    alert('Dados salvos!');
  };

  return (
    <div style={{display:'flex'}}>
      <MenuLateral
        clienteInfo={razaoSocial && cnpj ? (
          <>
            <div style={{fontWeight:700, fontSize: '1.1rem', color: '#fff'}}>{razaoSocial}</div>
            <div style={{fontWeight:500, fontSize: '0.95rem', color: '#fff'}}>CNPJ: {cnpj}</div>
          </>
        ) : null}
      />
      <div style={{marginLeft:210, width:'100%'}}>
        <form onSubmit={handleSubmit} style={{maxWidth: 400, margin: '32px auto', background: '#fff', padding: 24, borderRadius: 12, color: '#222', boxShadow: '0 2px 8px #0001'}}>
          <h2 style={{marginBottom: 24, color: '#153a6b'}}>Cadastro de Estação</h2>
          {campos.map((campo, idx) => (
            <div key={campo} style={{marginBottom: 16}}>
              <label style={{display: 'block', marginBottom: 4, color: '#222'}}>{campo}</label>
              {idx === 0 ? (
                <select
                  value={valores[0]}
                  onChange={e => handleChange(0, e.target.value)}
                  style={{width: '100%', padding: 8, borderRadius: 4, border: '1px solid #bbb', background: '#fff', color: '#222'}}
                >
                  <option value="">Selecione o ano</option>
                  <option value="2024">2024</option>
                  <option value="2025">2025</option>
                  <option value="2026">2026</option>
                </select>
              ) : idx === 5 || idx === 6 ? (
                <select
                  value={valores[idx]}
                  onChange={e => handleChange(idx, e.target.value)}
                  style={{width: '100%', padding: 8, borderRadius: 4, border: '1px solid #bbb', background: '#fff', color: '#222'}}
                >
                  <option value="">Selecione o estado</option>
                  <option value="AC">AC</option>
                  <option value="AL">AL</option>
                  <option value="AP">AP</option>
                  <option value="AM">AM</option>
                  <option value="BA">BA</option>
                  <option value="CE">CE</option>
                  <option value="DF">DF</option>
                  <option value="ES">ES</option>
                  <option value="GO">GO</option>
                  <option value="MA">MA</option>
                  <option value="MT">MT</option>
                  <option value="MS">MS</option>
                  <option value="MG">MG</option>
                  <option value="PA">PA</option>
                  <option value="PB">PB</option>
                  <option value="PR">PR</option>
                  <option value="PE">PE</option>
                  <option value="PI">PI</option>
                  <option value="RJ">RJ</option>
                  <option value="RN">RN</option>
                  <option value="RS">RS</option>
                  <option value="RO">RO</option>
                  <option value="RR">RR</option>
                  <option value="SC">SC</option>
                  <option value="SP">SP</option>
                  <option value="SE">SE</option>
                  <option value="TO">TO</option>
                </select>
              ) : idx === 7 ? (
                <select
                  value={valores[idx]}
                  onChange={e => handleChange(idx, e.target.value)}
                  style={{width: '100%', padding: 8, borderRadius: 4, border: '1px solid #bbb', background: '#fff', color: '#222'}}
                >
                  <option value="">Selecione o município</option>
                  {municipiosIBGE.map(m => (
                    <option key={m.codigo} value={m.nome}>{m.nome}</option>
                  ))}
                </select>
              ) : (
                <input
                  type="text"
                  value={valores[idx]}
                  onChange={e => handleChange(idx, e.target.value)}
                  style={{width: '100%', padding: 8, borderRadius: 4, border: '1px solid #bbb', background: '#fff', color: '#222'}}
                />
              )}
            </div>
          ))}
          <button type="submit" style={{marginTop: 16, padding: '8px 24px', borderRadius: 6, background: '#1976d2', color: '#fff', border: 'none', fontWeight: 600}}>Salvar</button>
        </form>
      </div>
    </div>
  );
}
